const url = 'https://www.youtube.com/oembed?url=' + encodeURIComponent('https://www.youtube.com/watch?v=5iRf37Z8Wd4') + '&format=json';
try {
  const res = await fetch(url, { headers: { 'user-agent': 'Mozilla/5.0' } });
  const text = await res.text();
  nodeRepl.write(JSON.stringify({ ok: res.ok, status: res.status, text: text.slice(0, 1000) }, null, 2));
} catch (e) {
  nodeRepl.write(String(e && e.stack || e));
}
